return ['x-generator'=>'GlotPress/4.0.1','translation-revision-date'=>'2021-07-27 08:30:43+0000','plural-forms'=>'nplurals=2; plural=n > 1;','project-id-version'=>'Themes - Twenty Fourteen','language'=>'id','messages'=>['In 2014, our default theme lets you create a responsive magazine website with a sleek, modern design. Feature your favorite homepage content in either a grid or a slider. Use the three widget areas to customize your website, and change your content\'s layout with a full-width page template and a contributor page to show off your authors. Creating a magazine website with WordPress has never been easier.'=>'Pada tahun 2014, tema default kami memungkinkan Anda membuat website majalah responsif dengan desain modern yang ramping. Tampilkan konten halaman depan favorit Anda baik di kolom atau slide. Gunakan tiga bidang widget untuk menyesuaikan situs web Anda, dan ubah tata letak konten anda dengan templet halaman penuh lebar dan halaman kontributor untuk memamerkan penulis anda. Membuat website majalah dengan WordPress belum pernah lebih mudah dari ini.','Twenty Fourteen'=>'Twenty Fourteen','Full Width Page'=>'Halaman Layar Penuh','Contributor Page'=>'Halaman Kontributor','Tag Archives: %s'=>'Arsip Tag: %s','Search Results for: %s'=>'Hasil Pencarian untuk: %s','Post format to show:'=>'Format tulisan yg ditampilkan:','Number of posts to show:'=>'Jumlah pos untuk ditampilkan:','Title:'=>'Judul:','%s <span class="meta-nav">&rarr;</span>'=>'%s <span class="meta-nav">&rarr;</span>','This gallery contains <a href="%1$s" rel="bookmark">%2$s photo</a>.'=>'Galeri ini memiliki <a href="%1$s" rel="bookmark">%2$s foto</a>.' . "\0" . 'Galeri ini memiliki <a href="%1$s" rel="bookmark">%2$s foto</a>.','Continue reading <span class="meta-nav">&rarr;</span>'=>'Lanjutkan membaca <span class="meta-nav">&rarr;</span>','More asides'=>'Aside lainnya','Asides'=>'Sampingan','More galleries'=>'Galeri Lainnya','Galleries'=>'Galeri','More links'=>'Tautan lainnya','More quotes'=>'K